export const ASSETS = RAW.trim().split("\n").map((l) => {
  const c = l.split("\t");
  return { tag: c[0], name: c[1] || "", type: c[2] || "", me: c[3] || "" };
});

export const ASSET_BY_TAG = (() => { const m = {}; for (const a of ASSETS) m[a.tag] = a; return m; })();

// Parse a tag into its location parts. parts: [site, building, level, zone, ...equip]
export function parseAssetTag(tag) {
  const p = String(tag || "").split(".");
  return { site: p[0] || "", building: p[1] || "", level: p[2] || "", zone: p[3] || "", equip: p.slice(4).join(".") };
}

// Given selected tags, derive the location/system to apply, using the deepest shared prefix.
// building/level/zone fill only where every selected asset agrees; system fills only if all share one type.
export function deriveFromAssets(tags) {
  const list = (tags || []).filter(Boolean);
  if (!list.length) return { area: "", subArea: "", tier3: "", system: "", partial: false };
  const parsed = list.map(parseAssetTag);
  const same = (key) => parsed.every((x) => x[key] === parsed[0][key]) ? parsed[0][key] : "";
  const building = same("building");
  const level = building ? same("level") : "";
  const zone = level ? same("zone") : "";
  const types = [...new Set(list.map((t) => (ASSET_BY_TAG[t] && ASSET_BY_TAG[t].type) || "").filter(Boolean))];
  const system = types.length === 1 ? types[0] : "";
  const partial = list.length > 1 && (!zone || !system);
  return { area: building, subArea: level, tier3: zone, system, partial };
}

// Split/join helpers so multiple tags live in the existing single 'asset' text field (no DB migration).
export function parseAssetField(val) {
  if (Array.isArray(val)) return val.filter(Boolean);
  return String(val || "").split(/[;\n,]+/).map((s) => s.trim()).filter(Boolean);
}
